//! Integration tests comparing Flex against PyTorch reference values
//! for non-contiguous tensor layouts beyond simple permutation.
//!
//! Reference values generated by `generate_strided_reference.py` using PyTorch.
//! Run with: cargo test -p burn-flex --test strided_ops_compare -- --nocapture

use burn_tensor::{Tensor, TensorData, s};

type E = burn_flex::Flex;

const TOL: f32 = 1e-5;

fn cmp(name: &str, actual: &TensorData, expected: &[f32]) {
    let a: Vec<f32> = actual.to_vec().unwrap();
    assert_eq!(a.len(), expected.len(), "{name}: length mismatch");
    let max_diff = a
        .iter()
        .zip(expected)
        .map(|(a, e)| (a - e).abs())
        .fold(0.0f32, f32::max);
    let status = if max_diff > TOL { "FAIL" } else { "ok" };
    eprintln!("  {status:>4} {name}: max_diff={max_diff:.2e}");
    assert!(
        max_diff <= TOL,
        "{name}: max_diff={max_diff:.2e} exceeds {TOL:.2e}"
    );
}

fn cmp_i32(name: &str, actual: &TensorData, expected: &[i32]) {
    let a: Vec<i32> = actual.to_vec().unwrap();
    assert_eq!(a.len(), expected.len(), "{name}: length mismatch");
    assert_eq!(a, expected, "{name}: integer results differ");
    eprintln!("    ok {name}");
}

fn t3(data: &[f32], shape: [usize; 3]) -> Tensor<E, 3> {
    Tensor::from_data(
        TensorData::new(data.to_vec(), shape.to_vec()),
        &Default::default(),
    )
}

