// === Scenario 3: narrow_transpose [2,4,3] -> narrow(1,1,2) -> swap(1,2) -> [2,3,2] ===

#[rustfmt::skip]
const NARROW_TRANS_A: &[f32] = &[1.0260185, 0.9245784, 1.2052674, 1.5442154, 1.0211217, 0.9420360, 0.9333035, 0.4518535, 1.4603022, 0.6621370, 0.4873863, 0.3659745, 1.3162974, 0.6911541, 1.2445183, 0.7700813, 1.3460120, 1.0638149, 1.9990540, 1.6732838, 0.1884504, 1.2052456, 1.7943112, 1.4501256];
