// === Scenario 4: step2_transpose [2,3,4] -> step-2 last -> swap(1,2) -> [2,2,3] ===

#[rustfmt::skip]
const STEP2_TRANS_A: &[f32] = &[0.4697416, 1.3546972, 1.7256585, 0.3872417, 1.9629065, 1.1173753, 0.7476047, 1.4613639, 1.8921787, 0.8602937, 0.2603362, 1.0589510, 1.4213481, 1.0972595, 1.2636514, 0.4852742, 0.3391419, 0.8158052, 1.8652655, 1.5304230, 1.0130157, 0.2441835, 0.4676929, 0.6367549];
#[rustfmt::skip]
const STEP2_TRANS_B: &[f32] = &[1.3839821, 1.2115834, 1.2882763, 0.3035916, 0.1454408, 0.9944780, 1.9860795, 0.6748825, 0.9334068, 1.5468975, 0.6155949, 0.3169948, 1.0594078, 0.1212219, 1.1802448, 1.6149076, 1.1973078, 0.7568927, 1.7990665, 1.2326014, 0.4227934, 0.1198085, 1.3874265, 0.2484691];

#[test]
fn test_ops_on_step_sliced_transposed() {
    eprintln!("\n=== step2_transpose: [2,3,4] -> [2,2,3] ===");
    let te = t3(STEP2_TRANS_A, [2, 3, 4])
        .slice(s![.., .., ..;2])
        .swap_dims(1, 2);
    let te2 = t3(STEP2_TRANS_B, [2, 3, 4])
        .slice(s![.., .., ..;2])
        .swap_dims(1, 2);

    // unary
    cmp(
        "step2_trans/sin",
        &te.clone().sin().into_data(),
        &[
            0.4526559, 0.9241048, 0.9487997, 0.9880328, 0.6798842, 0.2574055, 0.9888534, 0.3326780,
            0.8484319, 0.9532006, 0.9569563, 0.4508281,
        ],
    );
    cmp(
        "step2_trans/cos",
        &te.clone().cos().into_data(),
        &[
            0.8916853, -0.3821393, -0.3158784, -0.1542440, 0.7333195, 0.9663035, 0.1488925,
            0.9430405, 0.5293045, 0.3023385, -0.2902319, 0.8926108,
        ],
    );
    cmp(
        "step2_trans/exp",
        &te.clone().exp().into_data(),
        &[
            1.5995808, 7.1199913, 6.6338058, 5.6162181, 2.1119354, 1.2973661, 4.1427016, 1.4037426,
            2.7538936, 3.5383177, 6.4576502, 1.5963070,
        ],
    );
    cmp(
        "step2_trans/log",
        &te.clone().log().into_data(),
        &[
            -0.7555726, 0.6744263, 0.6377289, 0.5456088, -0.2908809, -1.3457813, 0.3516058,
            -1.0813367, 0.0129318, 0.2340055, 0.6234034, -0.7599434,
        ],
    );
    cmp(
        "step2_trans/sqrt",
        &te.clone().sqrt().into_data(),
        &[
            0.6853769, 1.4010377, 1.3755648, 1.3136432, 0.8646414, 0.5102316, 1.1922030, 0.5823589,
            1.0064869, 1.1241225, 1.3657472, 0.6838807,
        ],
    );
    cmp(
        "step2_trans/abs",
        &te.clone().abs().into_data(),
        &[
            0.4697416, 1.9629065, 1.8921787, 1.7256585, 0.7476047, 0.2603362, 1.4213481, 0.3391419,
            1.0130157, 1.2636514, 1.8652655, 0.4676929,
        ],
    );
    cmp(
        "step2_trans/neg",
        &te.clone().neg().into_data(),
        &[
            -0.4697416, -1.9629065, -1.8921787, -1.7256585, -0.7476047, -0.2603362, -1.4213481,
            -0.3391419, -1.0130157, -1.2636514, -1.8652655, -0.4676929,
        ],
    );
    // binary
    cmp(
        "step2_trans/add",
        &(te.clone() + te2.clone()).into_data(),
        &[
            1.8537236, 2.1083472, 2.8255854, 3.0139349, 2.7336841, 0.8759311, 2.4807558, 1.5364497,
            1.4358091, 2.4438963, 3.6643319, 1.8551193,
        ],
    );
    cmp(
        "step2_trans/mul",
        &(te.clone() * te2.clone()).into_data(),
        &[
            0.6501139, 0.2854866, 1.7661725, 2.2231250, 1.4848024, 0.1602616, 1.5057873, 0.4060572,
            0.4282964, 1.4914180, 3.3557367, 0.6488895,
        ],
    );
    cmp(
        "step2_trans/sub",
        &(te.clone() - te2.clone()).into_data(),
        &[
            -0.9142405, 1.8174658, 0.9587718, 0.4373822, -1.2384747, -0.3552586, 0.3619403,
            -0.8581660, 0.5902223, 0.0834066, 0.0661989, -0.9197336,
        ],
    );
    cmp(
        "step2_trans/div",
        &(te.clone() / te2.clone()).into_data(),
        &[
            0.3394130, 13.4962616, 2.0271747, 1.3395096, 0.3764224, 0.4229019, 1.3416439,
            0.2832537, 2.3960063, 1.0706688, 1.0367963, 0.3370938,
        ],
    );
    // reduce
    cmp(
        "step2_trans/sum_dim2",
        &te.clone().sum_dim(2).into_data(),
        &[4.3248267, 2.7335994, 2.7735057, 3.5966096],
    );
    cmp(
        "step2_trans/sum_dim1",
        &te.clone().sum_dim(1).into_data(),
        &[
            2.1954000, 2.7105112, 2.1525149, 2.6849995, 2.2044075, 1.4807086,
        ],
    );
    cmp(
        "step2_trans/mean_dim2",
        &te.clone().mean_dim(2).into_data(),
        &[1.4416089, 0.9111998, 0.9245019, 1.1988698],
    );
    cmp_i32(
        "step2_trans/argmax_dim2",
        &te.clone().argmax(2).into_data(),
        &[1_i32, 0_i32, 0_i32, 1_i32],
    );
    // softmax
    cmp(
        "step2_trans/softmax_dim2",
        &burn_tensor::activation::softmax(te.clone(), 2).into_data(),
        &[
            0.1041843, 0.4637410, 0.4320747, 0.6222598, 0.2339960, 0.1437442, 0.4991003, 0.1691187,
            0.3317809, 0.3052306, 0.5570650, 0.1377044,
        ],
    );
}

// === Scenario 5: expand_s0 [1,3,2] -> expand(2,3,2) -> [2,3,2] ===

#[rustfmt::skip]
const EXPAND_S0_A: &[f32] = &[1.2057246, 0.3543069, 1.6191434, 0.6835759, 1.3398824, 1.2600083];
#[rustfmt::skip]
const EXPAND_S0_B: &[f32] = &[0.3401771, 0.3635525, 0.6680823, 1.9045103, 0.1936396, 1.8114467];

#[test]
fn test_ops_on_expanded_stride0() {
    eprintln!("\n=== expand_s0: [1,3,2] -> [2,3,2] ===");
    let te = t3(EXPAND_S0_A, [1, 3, 2]).expand([2, 3, 2]);
    let te2 = t3(EXPAND_S0_B, [1, 3, 2]).expand([2, 3, 2]);

    // unary
    cmp(
        "expand_s0/sin",
        &te.clone().sin().into_data(),
        &[
            0.9340982, 0.3469404, 0.9988315, 0.6315695, 0.9734576, 0.9520929, 0.9340982, 0.3469404,
            0.9988315, 0.6315695, 0.9734576, 0.9520929,
        ],
    );
    cmp(
        "expand_s0/exp",
        &te.clone().exp().into_data(),
        &[
            3.3391776, 1.4251926, 5.0487633, 1.9809487, 3.8185942, 3.5254509, 3.3391776, 1.4251926,
            5.0487633, 1.9809487, 3.8185942, 3.5254509,
        ],
    );
    cmp(
        "expand_s0/neg",
        &te.clone().neg().into_data(),
        &[
            -1.2057246, -0.3543069, -1.6191434, -0.6835759, -1.3398824, -1.2600083, -1.2057246,
            -0.3543069, -1.6191434, -0.6835759, -1.3398824, -1.2600083,
        ],
    );
    cmp(
        "expand_s0/abs",
        &te.clone().abs().into_data(),
        &[
            1.2057246, 0.3543069, 1.6191434, 0.6835759, 1.3398824, 1.2600083, 1.2057246, 0.3543069,
            1.6191434, 0.6835759, 1.3398824, 1.2600083,
        ],
    );
    // binary
    cmp(
        "expand_s0/add",
        &(te.clone() + te2.clone()).into_data(),
        &[
            1.5459017, 0.7178594, 2.2872257, 2.5880861, 1.5335219, 3.0714550, 1.5459017, 0.7178594,
            2.2872257, 2.5880861, 1.5335219, 3.0714550,
        ],
    );
    cmp(
        "expand_s0/mul",
        &(te.clone() * te2.clone()).into_data(),
        &[
            0.4101599, 0.1288092, 1.0817211, 1.3018773, 0.2594542, 2.2824378, 0.4101599, 0.1288092,
            1.0817211, 1.3018773, 0.2594542, 2.2824378,
        ],
    );
    // reduce
    cmp(
        "expand_s0/sum_dim0",
        &te.clone().sum_dim(0).into_data(),
        &[
            2.4114492, 0.7086138, 3.2382867, 1.3671517, 2.6797647, 2.5200167,
        ],
    );
    cmp(
        "expand_s0/sum_dim2",
        &te.clone().sum_dim(2).into_data(),
        &[
            1.5600315, 2.3027191, 2.5998907, 1.5600315, 2.3027191, 2.5998907,
        ],
    );
    cmp(
        "expand_s0/mean_dim1",
        &te.clone().mean_dim(1).into_data(),
        &[1.3882500, 0.7659637, 1.3882500, 0.7659637],
    );
    // softmax
    cmp(
        "expand_s0/softmax_dim2",
        &burn_tensor::activation::softmax(te.clone(), 2).into_data(),
        &[
            0.7008644, 0.2991355, 0.7182035, 0.2817966, 0.5199579, 0.4800421, 0.7008644, 0.2991355,
            0.7182035, 0.2817966, 0.5199579, 0.4800421,
        ],
    );
}

// === Scenario 6: gather on step-sliced [2,2,4] -> step-2 -> [2,2,2] ===

#[rustfmt::skip]
const GATHER_INPUT: &[f32] = &[0.6434426, 1.6116502, 1.7280591, 0.7370160, 1.1400983, 0.4716576, 0.3295326, 1.5160065, 1.7335867, 1.0194312, 0.1160941, 0.7837191, 0.4837383, 0.7898995, 0.7730899, 0.2648920];

#[test]
fn test_gather_on_step_sliced() {
    eprintln!("\n=== gather on step-sliced [2,2,4] -> [2,2,2] ===");
    let te = t3(GATHER_INPUT, [2, 2, 4]).slice(s![.., .., ..;2]);

    let idx_data = TensorData::from([[[1_i32], [0]], [[0], [1]]]);
    let idx: Tensor<E, 3, burn_tensor::Int> = Tensor::from_data(idx_data, &Default::default());

    cmp(
        "gather/step2",
        &te.gather(2, idx).into_data(),
        &[1.7280591, 1.1400983, 1.7335867, 0.7730899],
    );
}
